SELECT COUNT(DISTINCT S.PK_SIAPE) AS QTD_SERVIDORES FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON C.SIAPE = S.PK_SIAPE WHERE LOWER(S.AREA_INGRESSO) LIKE LOWER('%filosofia%') AND LOWER(S.SIGLA_CAMPUS) = LOWER('jat') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND C.ANO = 2023 AND C.SEMESTRE = 2 AND C.SIGLA_CAMPUS = 'JAT' AND S.SAIU_DO_IFG = FALSE